import type { IDocumentLoader, IJsonLdContext } from 'jsonld-context-parser';
import type { IFetchOptions } from './Util';
import { Util } from './Util';

/**
 * A JSON-LD context document loader that is based on {@link Util#fetchCached}.
 */
export class DocumentLoaderCached implements IDocumentLoader {
  private readonly options: IFetchOptions;

  constructor(options: IFetchOptions) {
    this.options = options;
  }

  public async load(url: string): Promise<IJsonLdContext> {
    const { body } = await Util.fetchCached(url, this.options, { headers: { accept: 'application/ld+json' }});
    return JSON.parse(await require('stream-to-string')(body));
  }
}

/**
 * An error to indicate if a test should be skipped.
 */
export class ErrorSkipped extends Error {
  public readonly skipped: boolean;

  constructor(message?: string) {
    super(message);
    this.skipped = true;
  }
}

/**
 * Error to indicate that this is a test failure.
 */
export class ErrorTest extends Error {
  public readonly test: boolean;

  constructor(message?: string) {
    super(message);
    this.test = true;
  }
}

import { Transform } from 'node:stream';
import { Parser } from 'n3';

// Temporarily set format to text/n3 to allow blank node predicates (needed by JSON-LD tests)
const readPredicateOld = (<any> Parser.prototype)._readPredicate;
// Tslint:disable-next-line:only-arrow-functions
(<any> Parser.prototype)._readPredicate = function(token: any) {
  if (this.allowBlankNodePredicates) {
    this._n3Mode = true;
    this._quantified = {};
  }
  const ret = readPredicateOld.call(this, token);
  if (this.allowBlankNodePredicates) {
    this._n3Mode = false;
    delete this._quantified;
  }
  return ret;
};

export class GeneralizedN3StreamParser extends Transform {
  constructor(options: any) {
    super({ decodeStrings: true });

    (<any> this)._readableState.objectMode = true;

    // Set up parser
    const parser: any = new Parser(options);
    parser.allowBlankNodePredicates = true;
    // This is a workaround to resolve the RDF* syntax issue seen in
    // https://github.com/rubensworks/rdf-test-suite.js/pull/78#issue-1307275029
    parser._supportsRDFStar = true;

    let onData: any;
    let onEnd: any;
    // Pass dummy stream to obtain `data` and `end` callbacks
    parser.parse(
      {
        on: (event: any, callback: any) => {
          switch (event) {
            case 'data': onData = callback; break;
            case 'end': onEnd = callback; break;
          }
        },
      },
      // Handle quads by pushing them down the pipeline
      (error: any, quad: any) => error && this.emit('error', error) || quad && this.push(quad),
      // Emit prefixes through the `prefix` event
      (prefix: any, uri: any) => {
        this.emit('prefix', prefix, uri);
      },
    );

    // Implement Transform methods through parser callbacks
    this._transform = (chunk, encoding, done) => {
      onData(chunk); done();
    };
    this._flush = (done) => {
      onEnd(); done();
    };
  }
}

import type { RdfObjectLoader, Resource } from 'rdf-object';
import type { ITestCase } from './testcase/ITestCase';
import { testCaseFromResource } from './testcase/ITestCase';
import type { ITestCaseHandler } from './testcase/ITestCaseHandler';
import type { IFetchOptions } from './Util';
import { Util } from './Util';

/**
 * A manifest data holder.
 */
export interface IManifest {
  uri: string;
  label?: string;
  comment?: string;
  subManifests?: IManifest[];
  testEntries?: ITestCase<any>[];
  specifications?: Record<string, IManifest>;
}

/**
 * Create a manifest object from a resource.
 * @param {{[uri: string]: ITestCaseHandler<ITestCase<any>>}} testCaseHandlers Handlers for constructing test cases.
 * @param {IFetchOptions} options The fetch options.
 * @param {Resource} resource A resource.
 * @return {Promise<IManifest>} A promise resolving to a manifest object.
 */
export async function manifestFromResource(testCaseHandlers: Record<string, ITestCaseHandler<ITestCase<any>>>, options: IFetchOptions, resource: Resource, objectLoader: RdfObjectLoader): Promise<IManifest> {
  return {
    comment: resource.property.comment ? resource.property.comment.value : null,
    label: resource.property.label ? resource.property.label.value : null,
    specifications: resource.property.specifications ?
      await Util.promiseValues<IManifest>(
        Object.assign.apply({}, <any> await Promise.all(
          resource.property.specifications.list
            .map((specificationResource: Resource) =>
              ({ [specificationResource.term.value]:
                manifestFromSpecificationResource(testCaseHandlers, options, specificationResource, objectLoader) })),
        )),
      ) :
      null,
    subManifests: await Promise.all<IManifest>([].concat.apply([],
      // This is here because of the way the rdf-star test suite is published
      // @see https://github.com/rubensworks/rdf-test-suite.js/pull/78/files#r1026326410
        <any> ((resource.properties.include.length > 0 || !objectLoader) ?
          resource :
            (objectLoader.resources?.[resource.value.slice(0, resource.value.lastIndexOf('.')).replace(/\/manifest$/, '#manifest')] ?? resource)
        )
          .properties.include.map((includeList: Resource) =>
            includeList.list.map(res => manifestFromResource(testCaseHandlers, options, res, objectLoader))))),
    testEntries: (await Promise.all<ITestCase<any>>([].concat.apply([],
      // This is here because of the way the rdf-star test suite is published
      // @see https://github.com/rubensworks/rdf-test-suite.js/pull/78/files#r1026326410
        <any> (
          (resource.properties.entries.length > 0 || !objectLoader) ?
            resource :
              (objectLoader.resources?.[resource.value.slice(0, resource.value.lastIndexOf('.')).replace(/\/manifest$/, '#manifest')] ?? resource)
        ).properties.entries.map(
          (entryList: Resource) => (entryList.list || [ entryList ])
            .map(res => testCaseFromResource(testCaseHandlers, options, res, true)),
        ))))
      .filter(Boolean)
      .flat(),
    uri: resource.value,
  };
}

/**
 * Create a manifest object from a specification resource.
 * @param {{[uri: string]: ITestCaseHandler<ITestCase<any>>}} testCaseHandlers Handlers for constructing test cases.
 * @param {IFetchOptions} options The fetch options.
 * @param {Resource} resource A resource.
 * @return {Promise<IManifest>} A promise resolving to a manifest object.
 */
export async function manifestFromSpecificationResource(testCaseHandlers: Record<string, ITestCaseHandler<ITestCase<any>>>, options: IFetchOptions, resource: Resource, objectLoader: RdfObjectLoader): Promise<IManifest> {
  if (resource.property.conformanceRequirements) {
    const subManifests = await Promise.all<IManifest>(resource.property.conformanceRequirements.list
      .map(resource => manifestFromResource(testCaseHandlers, options, resource, objectLoader)));
    return {
      comment: resource.property.comment ? resource.property.comment.value : null,
      label: resource.property.label ? resource.property.label.value : null,
      subManifests,
      uri: resource.value,
    };
  }
  return {
    comment: resource.property.comment ? resource.property.comment.value : null,
    label: resource.property.label ? resource.property.label.value : null,
    uri: resource.value,
  };
}

import type { Resource } from 'rdf-object';
import { RdfObjectLoader } from 'rdf-object';
import { termToString } from 'rdf-string';
import type { IManifest } from './IManifest';
import { manifestFromResource } from './IManifest';
import type { ITestCase } from './testcase/ITestCase';
import type { ITestCaseHandler } from './testcase/ITestCaseHandler';
import type { IFetchOptions } from './Util';
import { Util } from './Util';

/**
 * A ManifestLoader loads test suites from URLs.
 */
export class ManifestLoader {
  public static readonly DEFAULT_TEST_CASE_HANDLERS: Record<string, ITestCaseHandler<ITestCase<any>>> =
    require('./testcase/TestCaseHandlers');

  public static readonly LOADER_CONTEXT = require('./context-manifest.json');

  private readonly testCaseHandlers: Record<string, ITestCaseHandler<ITestCase<any>>>;

  constructor(args?: IManifestLoaderArgs) {
    if (!args) {
      args = {};
    }
    this.testCaseHandlers = args.testCaseHandlers || ManifestLoader.DEFAULT_TEST_CASE_HANDLERS;
  }

  /**
   * Load the manifest from the given URL.
   * @param {string} url The URL of a manifest.
   * @param {IFetchOptions} options The fetch options.
   * @return {Promise<IManifest>} A promise that resolves to a manifest object.
   */
  public async from(url: string, options?: IFetchOptions): Promise<IManifest> {
    const objectLoader = new RdfObjectLoader({ context: ManifestLoader.LOADER_CONTEXT });
    const manifest: Resource = await this.import(objectLoader, url, options);
    return manifestFromResource(this.testCaseHandlers, options, manifest, objectLoader);
  }

  protected async import(objectLoader: RdfObjectLoader, urlInitial: string, options?: IFetchOptions): Promise<Resource> {
    const [ url, parsed ] = await Util.fetchRdf(urlInitial, options);
    // Dereference the URL and load it
    await objectLoader.import(parsed);

    // Import all sub-manifests
    let manifest: Resource =
      // First try the same URL as the document URL
      objectLoader.resources[url] ??
      // Also try extension-less manifest URL (needed for RDFa test suite)
      objectLoader.resources[url.slice(0, url.lastIndexOf('.'))] ??
      // Also try extension-less and with the last '/' replaced with a '#' (needed for RDFstar test suite)
      // @see https://github.com/w3c/rdf-star/issues/269
      objectLoader.resources[url.slice(0, url.lastIndexOf('.')).replace(/\/manifest$/, '#manifest')];

    if (!manifest) {
      throw new Error(`Could not find a resource ${url} in the document at ${url}`);
    }
    const includeJobs: Promise<any>[] = [];
    for (const includeList of manifest.properties.include) {
      for (const include of includeList.list) {
        if (include.term.termType !== 'NamedNode') {
          throw new Error(`Found invalid manifest term ${termToString(include.term)} when parsing ${url}`);
        }
        includeJobs.push(this.import(objectLoader, include.value, options));
      }
    }

    const jobs: Resource[] = await Promise.all(includeJobs);

    manifest =
      // First try the same URL as the document URL
      objectLoader.resources[url] ??
      // Also try extension-less manifest URL (needed for RDFa test suite)
      objectLoader.resources[url.slice(0, url.lastIndexOf('.'))] ??
      // Also try extension-less and with the last '/' replaced with a '#' (needed for RDFstar test suite)
      // @see https://github.com/w3c/rdf-star/issues/269
      objectLoader.resources[url.slice(0, url.lastIndexOf('.')).replace(/\/manifest$/, '#manifest')];

    return manifest;
  }
}

export interface IManifestLoaderArgs {
  testCaseHandlers?: Record<string, ITestCaseHandler<ITestCase<any>>>;
}

import type * as RDF from '@rdfjs/types';
import * as LogSymbols from 'log-symbols';
import { DataFactory } from 'rdf-data-factory';
import type { IManifest } from './IManifest';
import { ManifestLoader } from './ManifestLoader';
import type { ITestCase } from './testcase/ITestCase';
import WriteStream = NodeJS.WriteStream;
import { Util } from './Util';
import Timeout = NodeJS.Timeout;

// Tslint:disable:no-var-requires
const quad = require('rdf-quad');
const streamifyArray = require('streamify-array').streamifyArray;

const DF = new DataFactory();

export interface ITestSuiteConfig {
  exitWithStatusCode0: boolean;
  explicitApproval?: boolean;
  runRejected?: boolean;
  outputFormat: string;
  timeOutDuration: number;
  customEngingeOptions: object;
  specification?: string;
  cachePath?: string;
  testRegex?: RegExp;
  skipRegex?: RegExp;
  urlToFileMapping?: string;
}

/**
 * TestSuiteRunner runs a certain test suite manifest.
 */
export class TestSuiteRunner {
  /**
   * Parse an URL to file mapping string.
   * @param {string} urlToFileMapping An URL to file mapping string
   * @return {{url: string; path: string}[]} A parsed URL to file mapping array.
   */
  public fromUrlToMappingString(urlToFileMapping?: string): { url: string; path: string }[] {
    const urlToFileMappings: { url: string; path: string }[] = [];
    if (urlToFileMapping) {
      const [ url, path ]: string[] = urlToFileMapping.split('~');
      urlToFileMappings.push({ url, path });
    }
    return urlToFileMappings;
  }

  /**
   * Run the manifest with the given URL.
   * @param {string} manifestUrl The URL of a manifest.
   * @param handler The handler to run the tests with.
   * @param {string} cachePath The base directory to cache files in. If falsy, then no cache will be used.
   * @param {string} specification An optional specification to scope the manifest tests by.
   * @param {RegExp} testRegex An optional regex to filter test IRIs by.
   * @param {any} injectArguments An optional set of arguments to pass to the handler.
   * @return {Promise<ITestResult[]>} A promise resolving to an array of test results.
   */
  public async runManifest(manifestUrl: string, handler: any, config: ITestSuiteConfig): Promise<ITestResult[]> {
    const { cachePath, specification, urlToFileMapping } = config;
    const urlToFileMappings = this.fromUrlToMappingString(urlToFileMapping);
    const manifest: IManifest = await new ManifestLoader().from(manifestUrl, { cachePath, urlToFileMappings });
    const results: ITestResult[] = [];

    // Only run the tests for the given specification if one was defined.
    if (specification) {
      if (!manifest.specifications || !manifest.specifications[specification]) {
        return [];
      }
      await this.runManifestConcrete(manifest.specifications[specification], handler, config, results);
      return results;
    }

    await this.runManifestConcrete(manifest, handler, config, results);
    return results;
  }

  /**
   * Run the given manifest.
   * @param {string} manifest A manifest.
   * @param handler The handler to run the tests with.
   * @param {RegExp} testRegex An optional regex to filter test IRIs by.
   * @param {any} injectArguments An optional set of arguments to pass to the handler.
   * @param {ITestResult[]} results An array to append the test results to
   * @return {Promise<void>} A promise resolving when the tests are finished.
   */
  public async runManifestConcrete(
    manifest: IManifest,
    handler: any,
    config: ITestSuiteConfig,
    results: ITestResult[],
  ) {
    // Execute all tests in this manifest
    if (manifest.testEntries) {
      for (const test of manifest.testEntries) {
        if ((!config.testRegex || config.testRegex.test(test.uri)) && !(config.skipRegex && config.skipRegex.test(test.uri))) {
          if (!config.runRejected && test.approval === 'http://www.w3.org/ns/rdftest#Rejected') {
            // Skip tests that are explicitly rejected
            results.push({ test, ok: false, skipped: true, error: new Error('Rejected Test') });
          } else if (config.explicitApproval && test.approval !== 'http://www.w3.org/ns/rdftest#Approved') {
            // Skip tests that are explicitly rejected
            results.push({ test, ok: false, skipped: true, error: new Error('Test not explicitly approved') });
          } else {
            let timeout: Timeout = null;
            const timeStart = process.hrtime();
            let testResultOverride: ITestResultOverride | undefined;
            try {
              await Promise.race([
                test.test(handler, config.customEngingeOptions)
                  .then((result) => {
                    if (result) {
                      testResultOverride = result;
                    }
                  }),
                new Promise((res, rej) => {
                  // Global. is needed because TSC may otherwise pick the browser version of setTimeout, which returns int
                  timeout = global.setTimeout(
                    () => rej(new Error(`Test case '${test.uri}' timed out`)),
                    config.timeOutDuration,
                  );
                }),
              ]);
            } catch (error) {
              clearTimeout(timeout);
              results.push({ test, ok: false, error: <any> error, skipped: (<any> error).skipped });
              continue;
            }
            const timeEnd = process.hrtime(timeStart);
            clearTimeout(timeout);
            results.push({ test, ok: true, duration: (timeEnd[0] * 1000) + (timeEnd[1] / 1000000), ...testResultOverride });
          }
        }
      }
    }

    // Recursively handle all sub-manifests
    if (manifest.subManifests) {
      for (const subManifest of manifest.subManifests) {
        await (this.runManifestConcrete(subManifest, handler, config, results));
      }
    }
  }

  /**
   * Print the given test results to a text stream.
   * @param {WriteStream} stdout The output stream to write to.
   * @param {ITestResult[]} results An array of test results.
   * @param {boolean} compact If the results should be printed in compact-mode.
   */
  public resultsToText(stdout: WriteStream, results: ITestResult[], compact: boolean) {
    const failedTests: ITestResult[] = [];
    let success = 0;
    let skipped = 0;
    for (const result of results) {
      if (result.ok) {
        success++;
        stdout.write(`${LogSymbols.success} ${result.test.name} (${result.test.uri})${` ${Util.withColor(`${result.duration}ms`, Util.COLOR_GRAY)}`}\n`);
      } else if (result.skipped) {
        skipped++;
        stdout.write(`${LogSymbols.info} ${result.test.name} (${result.test.uri})\n`);
      } else {
        failedTests.push(result);
        stdout.write(`${LogSymbols.error} ${result.test.name} (${result.test.uri})\n`);
      }
    }

    if (!compact) {
      for (const result of failedTests) {
        stdout.write(`
${LogSymbols.error} ${Util.withColor(result.test.name, Util.COLOR_RED)}
  ${result.test.comment || ''}
  ${'test' in result.error ? result.error : result.error.stack}
  ${Util.withColor(`More info: ${result.test.uri}`, Util.COLOR_BLUE)}

`);
      }
    }

    const skippedString = skipped ? ` (skipped ${skipped})` : '';
    success += skipped;
    if (success === results.length) {
      stdout.write(`${LogSymbols.success} ${success} / ${results.length} tests succeeded!${skippedString}\n`);
    } else {
      stdout.write(`${LogSymbols.error} ${success} / ${results.length} tests succeeded!${skippedString}\n`);
    }
  }

  /**
   * Convert test results to an RDF stream.
   * @param {ITestResult[]} results Test results.
   * @param {IEarlProperties} properties EARL properties.
   * @param {Date} testDate The date at which the tests were executed.
   * @return {Stream} An RDF stream of quads.
   */
  public resultsToEarl(results: ITestResult[], properties: IEarlProperties, testDate: Date): RDF.Stream {
    const p = require('./prefixes.json');
    const dateRaw = testDate.toISOString();
    const date = `"${dateRaw}"^^${p.xsd}dateTime`;
    const quads: RDF.Quad[] = [];

    // Describe report
    const report = properties.reportUri || '';
    quads.push(DF.quad(DF.namedNode(report), DF.namedNode(`${p.foaf}primaryTopic`), DF.namedNode(properties.applicationUri)));
    quads.push(DF.quad(DF.namedNode(report), DF.namedNode(`${p.dc}issued`), DF.literal(testDate.toISOString(), DF.namedNode(`${p.xsd}dateTime`))));
    for (const author of properties.authors) {
      quads.push(DF.quad(DF.namedNode(report), DF.namedNode(`${p.foaf}maker`), DF.namedNode(author.uri)));
    }

    // Describe application
    const app = properties.applicationUri;
    quads.push(quad(app, `${p.rdf}type`, `${p.earl}Software`));
    quads.push(quad(app, `${p.rdf}type`, `${p.earl}TestSubject`));
    quads.push(quad(app, `${p.rdf}type`, `${p.doap}Project`));
    quads.push(quad(app, `${p.doap}name`, `"${properties.applicationNameFull}"`));
    quads.push(quad(app, `${p.dc}title`, `"${properties.applicationNameFull}"`));
    if (properties.version) {
      quads.push(quad(app, `${p.doap}release`, '_:b_release'));
      quads.push(quad('_:b_release', `${p.doap}revision`, `"${properties.version}"`));
    }
    quads.push(quad(app, `${p.doap}homepage`, properties.applicationHomepageUrl));
    quads.push(quad(app, `${p.doap}license`, properties.licenseUri));
    quads.push(quad(app, `${p.doap}programming-language`, '"JavaScript"'));
    for (const spec of properties.specificationUris) {
      quads.push(quad(app, `${p.doap}implements`, spec));
    }
    quads.push(quad(app, `${p.doap}category`, 'http://dbpedia.org/resource/Resource_Description_Framework'));
    quads.push(quad(app, `${p.doap}download-page`, `https://npmjs.org/package/${properties.applicationNameNpm}`));
    if (properties.applicationBugsUrl) {
      quads.push(quad(app, `${p.doap}bug-database`, properties.applicationBugsUrl));
    }
    if (properties.applicationBlogUrl) {
      quads.push(quad(app, `${p.doap}blog`, properties.applicationBlogUrl));
    }
    for (const author of properties.authors) {
      quads.push(quad(app, `${p.doap}developer`, author.uri));
      quads.push(quad(app, `${p.doap}maintainer`, author.uri));
      quads.push(quad(app, `${p.doap}documenter`, author.uri));
      quads.push(quad(app, `${p.doap}maker`, author.uri));
      quads.push(quad(app, `${p.dc}creator`, author.uri));
    }
    quads.push(quad(app, `${p.dc}description`, `"${properties.applicationDescription}"@en`));
    quads.push(quad(app, `${p.doap}description`, `"${properties.applicationDescription}"@en`));

    // Describe authors
    for (const author of properties.authors) {
      quads.push(quad(author.uri, `${p.rdf}type`, `${p.foaf}Person`));
      quads.push(quad(author.uri, `${p.rdf}type`, `${p.earl}Assertor`));
      if (author.name) {
        quads.push(quad(author.uri, `${p.foaf}name`, `"${author.name}"`));
      }
      if (author.homepage) {
        quads.push(quad(author.uri, `${p.foaf}homepage`, author.homepage));
      }
      if (author.primaryTopic) {
        quads.push(quad(author.uri, `${p.foaf}primaryTopicOf`, author.primaryTopic));
      }
    }

    // Describe test results
    let id = 0;
    for (const result of results) {
      const testUri = result.test.uri;
      quads.push(quad(testUri, `${p.rdf}type`, `${p.earl}TestCriterion`));
      quads.push(quad(testUri, `${p.rdf}type`, `${p.earl}TestCase`));
      quads.push(quad(testUri, `${p.dc}title`, `"${result.test.name}"`));
      if (result.test.comment) {
        quads.push(quad(testUri, `${p.dc}description`, `"${result.test.comment}"`));
      }
      quads.push(quad(testUri, `${p.earl}assertions`, `_:assertions${id}`));
      quads.push(quad(`_:assertions${id}`, `${p.rdf}first`, `_:assertion${id}`));
      quads.push(quad(`_:assertions${id}`, `${p.rdf}rest`, `${p.rdf}nil`));
      quads.push(quad(`_:assertion${id}`, `${p.rdf}type`, `${p.earl}Assertion`));
      for (const author of properties.authors) {
        quads.push(quad(`_:assertion${id}`, `${p.earl}assertedBy`, author.uri));
      }
      quads.push(quad(`_:assertion${id}`, `${p.earl}test`, testUri));
      quads.push(quad(`_:assertion${id}`, `${p.earl}subject`, app));
      quads.push(quad(`_:assertion${id}`, `${p.earl}mode`, `${p.earl}automatic`));
      quads.push(quad(`_:assertion${id}`, `${p.earl}result`, `_:result${id}`));
      quads.push(quad(`_:result${id}`, `${p.rdf}type`, `${p.earl}TestResult`));
      quads.push(quad(`_:result${id}`, `${p.earl}outcome`, p.earl + (result.ok ? 'passed' : (result.skipped ? 'inapplicable' : 'failed'))));
      quads.push(quad(`_:result${id}`, `${p.dc}date`, date));
      id++;
    }

    return streamifyArray(quads);
  }

  /**
   * Create an {#link IEarlProperties} data object based on package.json contents.
   * @param packageJson Package.json contents.
   * @return {IEarlProperties} A data object.
   */
  public packageJsonToEarlProperties(packageJson: any): IEarlProperties {
    return {
      applicationBugsUrl: packageJson.bugs && packageJson.bugs.url ? packageJson.bugs.url : packageJson.bugs,
      applicationDescription: packageJson.description,
      applicationHomepageUrl: packageJson.homepage,
      applicationNameFull: packageJson.name,
      applicationNameNpm: packageJson.name,
      applicationUri: packageJson.name ? `https://www.npmjs.com/package/${packageJson.name}/` : null,
      authors: [
        {
          homepage: null,
          name: packageJson.author,
          uri: `https://www.npmjs.com/package/${packageJson.name}/#author`,
        },
      ],
      licenseUri: packageJson.license ? Util.licenseToUri(packageJson.license) : null,
      reportUri: null,
      specificationUris: [],
      version: packageJson.version,
    };
  }
}

