(<any> global).fetch = (url: string) => {
  let body;
  switch (url) {
    case 'http://example.org/':
      body = streamifyString('{ "a": "b" }');
      break;
    default:
      return Promise.reject(new Error('Fetch error'));
  }
  return Promise.resolve(new Response(body, <any> { headers: new Headers({ a: 'b' }), status: 200 }));
};

describe('DocumentLoaderCached', () => {
  const loader = new DocumentLoaderCached({});

  describe('#load', () => {
    it('should reject on 404s', () => {
      return expect(loader.load('404')).rejects.toBeTruthy();
    });

    it('should load documents', async() => {
      const spy = jest.spyOn(<any> global, 'fetch');

      const response1 = await loader.load('http://example.org/');
      expect(response1).toEqual({ a: 'b' });

      expect(spy).toHaveBeenCalledTimes(1);
    });
  });
});

import { ErrorSkipped } from '../lib/ErrorSkipped';

describe('ErrorSkipped', () => {
  it('should be constructable with arg', () => {
    return expect(new ErrorSkipped('abc')).toBeInstanceOf(Error);
  });

  it('should be constructable without arg', () => {
    return expect(new ErrorSkipped()).toBeInstanceOf(Error);
  });

  it('should expose the skipped field', () => {
    return expect(new ErrorSkipped().skipped).toBe(true);
  });
});

import 'jest-rdf';
import { arrayifyStream } from 'arrayify-stream';
import { StreamParser } from 'n3';
import { GeneralizedN3StreamParser } from '../lib/GeneralizedN3StreamParser';

// Tslint:disable:no-var-requires
const quad = require('rdf-quad');
const streamifyString = require('streamify-string');

describe('GeneralizedN3StreamParser', () => {
  let parser;

  beforeEach(() => {
    parser = new GeneralizedN3StreamParser({ format: 'text/turtle' });
  });

  it('should parse blank nodes as predicates', async() => {
    return await expect(arrayifyStream(streamifyString(`
@prefix foo: <http://example.org/ns#> .
_:s _:p _:o.`).pipe(parser))).resolves
      .toEqualRdfQuadArray([
        quad('_:s', '_:p', '_:o'),
      ]);
  });

  it('should emit errors on invalid turtle', async() => {
    return expect(arrayifyStream(streamifyString(`.`).pipe(parser))).rejects.toThrow();
  });

  it('should not break regular N3 Turtle parser', async() => {
    return expect(arrayifyStream(streamifyString(`
@prefix foo: <http://example.org/ns#> .
_:s _:p _:o.`).pipe(new StreamParser({ format: 'text/turtle' }))))
      .rejects.toThrow('Disallowed blank node as predicate on line 3.');
  });
});

