import { ErrorTest } from '../lib/ErrorTest';

import 'jest-rdf';
import * as LogSymbols from 'log-symbols';
import { PassThrough } from 'node:stream';
import type { ITestSuiteConfig } from '../lib/TestSuiteRunner';
import { TestSuiteRunner } from '../lib/TestSuiteRunner';
import { Util } from '../lib/Util';
import { arrayifyStream } from 'arrayify-stream';

const mockTest1 = {
  name: 'Test1',
  test: () => Promise.resolve(),
  uri: 'http://ex.org/test1',
};
const mockTest2 = {
  comment: 'Test2 comment',
  name: 'Test2',
  test: () => Promise.resolve(2),
  uri: 'http://ex.org/test2',
};
const mockTest3 = {
  name: 'Test3',
  test: () => Promise.reject(new ErrorTest('Fail')),
  uri: 'http://ex.org/test3',
};
const mockTest4 = {
  comment: 'Test4 comment',
  name: 'Test4',
  test: () => Promise.resolve({ duration: 1337 }),
  uri: 'http://ex.org/test4',
};
const mockTest5 = {
  comment: 'Test5 comment',
  approval: 'http://www.w3.org/ns/rdftest#Rejected',
  name: 'Test5',
  test: () => Promise.resolve(),
  uri: 'http://ex.org/test5',
};
const mockTest6 = {
  comment: 'Test6 comment',
  approval: 'http://www.w3.org/ns/rdftest#Approved',
  name: 'Test6',
  test: () => Promise.resolve(),
  uri: 'http://ex.org/test6',
};

const timeOutMockTest1 = {
  name: 'Timeout1',
  test: () => {
    return new Promise<void>((resolve, reject) => setTimeout(() => resolve(), 500));
  },
  uri: 'http://ex.org/timeout1',
};

const defaultConfig: ITestSuiteConfig = {
  customEngingeOptions: {},
  exitWithStatusCode0: false,
  outputFormat: 'detailed',
  timeOutDuration: 3000,
};

// Mock ManifestLoader
jest.mock<typeof import('../lib/ManifestLoader')>('../lib/ManifestLoader', () => ({
  ManifestLoader: function ManifestLoader() {
    return {
      from: (manifestUrl: string, cachePath: string) => {
        if (manifestUrl === 'valid') {
          return Promise.resolve({
            testEntries: [
              mockTest1,
              mockTest2,
              mockTest3,
              mockTest5,
              mockTest6,
            ],
            uri: manifestUrl,
          });
        } if (manifestUrl === 'validsub') {
          return Promise.resolve({
            subManifests: [
              {
                testEntries: [
                  mockTest1,
                ],
                uri: manifestUrl,
              },
              {
                testEntries: [
                  mockTest2,
                  mockTest3,
                ],
                uri: manifestUrl,
              },
            ],
            uri: manifestUrl,
          });
        } if (manifestUrl === 'validspec') {
          return Promise.resolve({
            specifications: {
              spec1: {
                testEntries: [
                  mockTest1,
                  mockTest2,
                  mockTest3,
                ],
                uri: manifestUrl,
              },
            },
            uri: manifestUrl,
          });
        } if (manifestUrl === 'timeout') {
          return Promise.resolve({
            testEntries: [ timeOutMockTest1 ],
            uri: manifestUrl,
          });
        } if (manifestUrl === 'override') {
          return Promise.resolve({
            testEntries: [
              mockTest4,
            ],
            uri: manifestUrl,
          });
        }
        return Promise.resolve({
          uri: manifestUrl,
        });
      },
    };
  },
}));

// Mock time measurements
(<any> process).hrtime = () => {
  return [ 1, 1 ];
};

// Tslint:disable:no-var-requires
const quad = require('rdf-quad');
const stringifyStream = require('stream-to-string');

describe('TestSuiteRunner', () => {
  let runner;
  let handler;

  beforeEach(() => {
    runner = new TestSuiteRunner();
    handler = () => true;
  });

  describe('fromUrlToMappingString', () => {
    it('should be empty for a falsy string', () => {
      return expect(runner.fromUrlToMappingString(null)).toEqual([]);
    });

    it('should parse a valid string', () => {
      return expect(runner.fromUrlToMappingString(
        'https://w3c.github.io/json-ld-api/~/my/path/to/file/',
      )).toEqual([
        { url: 'https://w3c.github.io/json-ld-api/', path: '/my/path/to/file/' },
      ]);
    });
  });

  describe('runManifest', () => {
    it('should produce an empty array for an empty manifest', () => {
      return expect(runner.runManifest('empty', handler, defaultConfig)).resolves.toEqual([]);
    });

    it('should produce results for a valid manifest', () => {
      return expect(runner.runManifest('valid', handler, defaultConfig)).resolves.toEqual([
        {
          ok: true,
          test: mockTest1,
          duration: 1000.000001,
        },
        {
          ok: true,
          test: mockTest2,
          duration: 1000.000001,
        },
        {
          error: new Error('Fail'),
          ok: false,
          test: mockTest3,
        },
        {
          error: new Error('Rejected Test'),
          ok: false,
          skipped: true,
          test: mockTest5,
        },
        {
          ok: true,
          test: mockTest6,
          duration: 1000.000001,
        },
      ]);
    });

    it('should produce results for a valid manifest with submanifests', () => {
      return expect(runner.runManifest('validsub', handler, defaultConfig)).resolves.toEqual([
        {
          ok: true,
          test: mockTest1,
          duration: 1000.000001,
        },
        {
          ok: true,
          test: mockTest2,
          duration: 1000.000001,
        },
        {
          error: new Error('Fail'),
          ok: false,
          test: mockTest3,
        },
      ]);
    });

    it('should produce empty results for a valid manifest without the requested specifications', () => {
      const config: ITestSuiteConfig = { ...defaultConfig, specification: 'spec1' };
      return expect(runner.runManifest('valid', handler, config)).resolves.toEqual([]);
    });

    it('should produce results for a valid manifest with the requested specifications', () => {
      const config: ITestSuiteConfig = { ...defaultConfig, specification: 'spec1' };
      return expect(runner.runManifest('validspec', handler, config)).resolves.toEqual([
        {
          ok: true,
          test: mockTest1,
          duration: 1000.000001,
        },
        {
          ok: true,
          test: mockTest2,
          duration: 1000.000001,
        },
        {
          error: new Error('Fail'),
          ok: false,
          test: mockTest3,
        },
      ]);
    });

    it('should handle testcases that time out', (next) => {
      const config: ITestSuiteConfig = { ...defaultConfig, timeOutDuration: 200 };
      runner.runManifest('timeout', handler, config)
        .then((results) => {
          expect(results).toEqual([{
            error: new Error('Test case \'http://ex.org/timeout1\' timed out'),
            ok: false,
            skipped: undefined,
            test: timeOutMockTest1,
          }]);
          next();
        })
        .catch((err) => {
          next.fail(err);
          next();
        });
    });

    it('should produce results for a valid manifest with a non-matching test regex', () => {
      const config: ITestSuiteConfig = { ...defaultConfig, testRegex: /abc/ };
      return expect(runner.runManifest('valid', handler, config)).resolves.toEqual([]);
    });

    it('should produce results for a valid manifest with a single-matching test regex', () => {
      const config: ITestSuiteConfig = { ...defaultConfig, testRegex: /1/ };
      return expect(runner.runManifest('valid', handler, config)).resolves.toEqual([
        {
          ok: true,
          test: mockTest1,
          duration: 1000.000001,
        },
      ]);
    });

    it('should produce results for a valid manifest with a multiple-matching test regex', () => {
      const config: ITestSuiteConfig = { ...defaultConfig, testRegex: /^.*test.*$/ };
      return expect(runner.runManifest('valid', handler, config)).resolves.toEqual([
        {
          ok: true,
          test: mockTest1,
          duration: 1000.000001,
        },
        {
          ok: true,
          test: mockTest2,
          duration: 1000.000001,
        },
        {
          error: new Error('Fail'),
          ok: false,
          test: mockTest3,
        },
        {
          error: new Error('Rejected Test'),
          ok: false,
          skipped: true,
          test: mockTest5,
        },
        {
          ok: true,
          test: mockTest6,
          duration: 1000.000001,
        },
      ]);
    });

    it('should produce results for a valid manifest with a non-matching skip regex', () => {
      const config: ITestSuiteConfig = { ...defaultConfig, skipRegex: /abc/ };
      return expect(runner.runManifest('valid', handler, config)).resolves.toEqual([
        {
          ok: true,
          test: mockTest1,
          duration: 1000.000001,
        },
        {
          ok: true,
          test: mockTest2,
          duration: 1000.000001,
        },
        {
          error: new Error('Fail'),
          ok: false,
          test: mockTest3,
        },
        {
          error: new Error('Rejected Test'),
          ok: false,
          skipped: true,
          test: mockTest5,
        },
        {
          ok: true,
          test: mockTest6,
          duration: 1000.000001,
        },
      ]);
    });

    it('should produce results for a valid manifest with a single-matching skip regex', () => {
      const config: ITestSuiteConfig = { ...defaultConfig, skipRegex: /1/ };
      return expect(runner.runManifest('valid', handler, config)).resolves.toEqual([
        {
          ok: true,
          test: mockTest2,
          duration: 1000.000001,
        },
        {
          error: new Error('Fail'),
          ok: false,
          test: mockTest3,
        },
        {
          error: new Error('Rejected Test'),
          ok: false,
          skipped: true,
          test: mockTest5,
        },
        {
          ok: true,
          test: mockTest6,
          duration: 1000.000001,
        },
      ]);
    });

    it('should produce results for a valid manifest with a multiple-matching skip regex', () => {
      const config: ITestSuiteConfig = { ...defaultConfig, skipRegex: /^.*test.*$/ };

      return expect(runner.runManifest('valid', handler, config)).resolves.toEqual([]);
    });

    it('should produce results for a valid manifest requiring explicit approval to run tests', () => {
      const config: ITestSuiteConfig = { ...defaultConfig, explicitApproval: true };
      return expect(runner.runManifest('valid', handler, config)).resolves.toEqual([
        {
          error: new Error('Test not explicitly approved'),
          ok: false,
          skipped: true,
          test: mockTest1,
        },
        {
          error: new Error('Test not explicitly approved'),
          ok: false,
          skipped: true,
          test: mockTest2,
        },
        {
          error: new Error('Test not explicitly approved'),
          ok: false,
          skipped: true,
          test: mockTest3,
        },
        {
          error: new Error('Rejected Test'),
          ok: false,
          skipped: true,
          test: mockTest5,
        },
        {
          ok: true,
          test: mockTest6,
          duration: 1000.000001,
        },
      ]);
    });

    it('should handle test result overrides', () => {
      return expect(runner.runManifest('override', handler, defaultConfig)).resolves.toEqual([
        {
          ok: true,
          test: mockTest4,
          duration: 1337,
        },
      ]);
    });
  });

  describe('resultsToText', () => {
    const testResults = [
      {
        ok: true,
        duration: 10,
        test: mockTest1,
      },
      {
        ok: true,
        duration: 10,
        test: mockTest2,
      },
      {
        error: new ErrorTest('Fail'),
        ok: false,
        test: mockTest3,
      },
    ];
    const testResultsSkips = [
      {
        ok: true,
        duration: 10,
        test: mockTest1,
      },
      {
        ok: false,
        skipped: true,
        test: mockTest2,
      },
      {
        ok: false,
        skipped: true,
        test: mockTest3,
      },
      {
        error: new ErrorTest('Fail'),
        ok: false,
